def next_published_version(active_version: str) -> str:
	"""Return the next published version by incrementing the final numeric segment."""

	parts = active_version.split(".")
	last = parts[-1]
	if last.isdigit():
		return ".".join([*parts[:-1], str(int(last) + 1)])
